GET_FIELD = "targetField";    //private static final String KEY_OBJ_TYPE_SPLIT = "#";    //    public static String parseObjectTypeName(String value) {    //        return StringUtils.substringBefore(value, KEY_OBJ_TYPE_SPLIT);    //    }    @FormField(ordinal = 0, type = FormFieldType.ENUM, validate = {Validator.require})    public String objectType;    public String getObjectType() {        return (this.objectType);    }    @FormField(ordinal = 1, type = FormFieldType.ENUM, validate = {Validator.require})    public String targetField;    public static List<OptionWithEndType> getObjectTypeOpts() {        IPluginContext pluginContext = IPluginContext.getThreadLocalInstance();        OntologyPluginMeta meta = OntologyPluginMeta.createPluginMeta(pluginContext.getContext());        List<OptionWithEndType> result = Lists.newArrayList();        for (OntologyObjectType objType : OntologyObjectType.load(meta.getDomain())) {            result.add(new OptionWithEndType(objType.getName(),                    objType.getName(),                    IEndTypeGetter.EndType.OntologyObjectType));        }        return result;    }    @TISExtension    public static class DftDesc extends Descriptor<LinkReference> {        @Override        public String getDisplayName() {            return "Reference";        }        public DftDesc() {            super();            final String[] targetFields = getValueChangePipeTargetField();            for (String targetField : targetFields) {                this.registerSelectOptions(targetField, Collections::emptyList);            }            this.valueChangePipe(KEY_OBJECT_TYPE, targetFields)                    .render((pluginMeta, param) -> {                        JSONObject result = new JSONObject();                        OntologyPluginMeta meta = OntologyPluginMeta.createPluginMeta(pluginMeta);                        //                        String[] pair = StringUtils.split();                        //                        if (pair.length != 2) {                        //                            throw new IllegalStateException(param.getString                        //                            (KEY_OBJECT_TYPE) + " is illegal");                        //                        }                        OntologyObjectType objectType = OntologyObjectType.loadDetail(meta.getDomain(),                                param.getString(KEY_OBJECT_TYPE));                        List<OntologyProperty> cols = objectType.getCols();                        List<OptionWithEndType> colOpts = Lists.newArrayList();                        for (OntologyProperty col : cols) {                            colOpts.add(new OptionWithEndType(col.getName(), col.getName(),                                    col.parseOntologyType().getEndType()));                        }                        for (String targetField : targetFields) {                            result.put(targetField, Option.toJson(colOpts));                        }                        return result;                    });        }        protected String[] getValueChangePipeTargetField() {            return new String[]{KEY_TARGET_FIELD};        }    }}